{ pkgs, ... }:
{
  systemd.services.rollback-gate = {
    description = "NixOS dead-man's switch: revert unless a staged repair was committed in time";

    serviceConfig = {
      Type = "oneshot";
      ExecStart = pkgs.writeShellScript "rollback-gate-expire" ''
        echo "rollback-gate: confirmation deadline expired without commit; reverting to boot default" >&2
        exit 1
      '';
      FailureAction = "reboot-force";
    };
  };

  systemd.timers.rollback-gate = {
    description = "Dead-man's switch deadline; armed at staging, disarmed on commit";
    timerConfig = {
      OnActiveSec = "180s";
      Unit = "rollback-gate.service";
    };
  };
}

{ config, pkgs, lib, ... }:
let
  cfg = config.services.vigilAutoReconciler;
in
{
  options.services.vigilAutoReconciler = {
    enable = lib.mkEnableOption "vigil NixOS auto-reconciler";
    branch = lib.mkOption {
      type = lib.types.str;
      description = "Git branch to track for NixOS config reconciliation.";
    };
  };

  config = lib.mkIf cfg.enable {
    systemd.services.vigil-auto-reconcile = {
      description = "Vigil NixOS auto-reconciler";
      path = [ pkgs.git pkgs.hostname pkgs.nixos-rebuild pkgs.util-linux ];
      serviceConfig = {
        Type = "oneshot";
        RemainAfterExit = false;
        ExecStart = pkgs.writeShellScript "vigil-auto-reconcile" ''
          set -euo pipefail
          BRANCH="${cfg.branch}"
          STATE_FILE="/var/lib/vigil-reconciler/last-sha"
          mkdir -p "$(dirname "$STATE_FILE")"
          git -C /opt/nixos-config fetch origin
          NEW=$(git -C /opt/nixos-config rev-parse "origin/$BRANCH")
          git -C /opt/nixos-config reset --hard "origin/$BRANCH"
          OLD=$(cat "$STATE_FILE" 2>/dev/null || echo "")
          if [ "$NEW" != "$OLD" ]; then
            flock /var/lock/vigil-nixos-rebuild nixos-rebuild switch --flake "/opt/nixos-config#$(hostname)"
            echo "$NEW" > "$STATE_FILE"
          fi
        '';
      };
    };

    systemd.timers.vigil-auto-reconcile = {
      description = "Timer for vigil NixOS auto-reconciler";
      wantedBy = [ "multi-user.target" ];
      timerConfig = {
        OnBootSec = "300s";
        OnUnitActiveSec = "300s";
        Unit = "vigil-auto-reconcile.service";
      };
    };
  };
}

